s+='</g>';
// Minor every odd kW
s+='<g stroke="#24272c" stroke-width="0.5">';
for(var g=yMin+1;g<yMax;g+=2){s+='<line x1="'+PL+'" y1="'+yP(g).toFixed(1)+'" x2="'+(VW-PR)+'" y2="'+yP(g).toFixed(1)+'"/>';}
s+='</g>';
