}
s+='<text x="'+(VW-PR+5)+'" y="'+(PT-2)+'" fill="#d8d9da" font-size="10" font-weight="800" letter-spacing=".05em">K\u010d</text>';
s+='</g>';

// X-axis labels (every 3h, skip near NOW)
