// Build SVG path from [{m,v}]
function bp(pts){
  if(pts.length<2)return"";
  var d="M"+xP(pts[0].m).toFixed(1)+","+yP(pts[0].v).toFixed(1);
  for(var i=1;i<pts.length;i++){d+=" L"+xP(pts[i].m).toFixed(1)+","+yP(pts[i].v).toFixed(1);}
  return d;
}

// Solar: area fill + line
